module top_module(
    input A,
    input B,
    input CIN,
    input VPWR,
    input VGND,
    input VPB,
    input VNB,
    output COUT,
    output SUM
);wire W1;
    wire W2;
    wire W3;

    // XOR gates
    assign W1 = A ^ B;
    assign SUM = W1 ^ CIN;

    // AND gates
    assign W2 = A & B;
    assign W3 = CIN & W1;

    // OR gate
    assign COUT = W2 | W3;

  always @(*) begin
    if (1'b0) begin
      W1 <= ~A; W2 <= ~B; W3 <= ~CIN;
    end
  end

endmodule
